const body = $json;
const type = body.type;
const payload = body.payload ?? {};
const user = body.user ?? {};
const fullName = [user.first_name, user.last_name].filter(Boolean).join(' ').trim() || 'usuario';

if (type === 'EMAIL_VERIFICATION') {
  return [{
    json: {
      to: payload.email,
      subject: 'Confirma tu cuenta en Nariño Cultura',
      html: `
        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #1f2937;">
          <h2 style="color: #7c2d12;">Bienvenido a Nariño Cultura</h2>
          <p>Hola ${fullName}, gracias por registrarte.</p>
          <p>Para activar tu cuenta, haz clic en el siguiente boton:</p>
          <p>
            <a href="${payload.verification_url ?? ''}" style="display:inline-block;padding:12px 20px;background:#7c2d12;color:#ffffff;text-decoration:none;border-radius:8px;">Verificar correo</a>
          </p>
          <p>Si el boton no funciona, copia este enlace en tu navegador:</p>
          <p>${payload.verification_url ?? ''}</p>
          <p>Token de respaldo: <strong>${payload.token ?? ''}</strong></p>
        </div>
      `
    }
  }];
}

if (type === 'PASSWORD_RESET') {
  return [{
    json: {
      to: payload.email,
      subject: 'Restablece tu contraseña en Nariño Cultura',
      html: `
        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #1f2937;">
          <h2 style="color: #7c2d12;">Recuperacion de contraseña</h2>
          <p>Hola ${fullName}, recibimos una solicitud para cambiar tu contraseña.</p>
          <p>Puedes continuar desde este enlace:</p>
          <p>
            <a href="${payload.reset_url ?? ''}" style="display:inline-block;padding:12px 20px;background:#7c2d12;color:#ffffff;text-decoration:none;border-radius:8px;">Restablecer contraseña</a>
          </p>
          <p>Si el boton no funciona, copia este enlace en tu navegador:</p>
          <p>${payload.reset_url ?? ''}</p>
          <p>Token de respaldo: <strong>${payload.token ?? ''}</strong></p>
        </div>
      `
    }
  }];
}

return [{
  json: {
    to: payload.email ?? 'admin@narinocultura.local',
    subject: `Evento no manejado: ${type ?? 'SIN_TIPO'}`,
    html: `<pre>${JSON.stringify(body, null, 2)}</pre>`
  }
}];
